+    #[cfg(windows)]
+    async fn exec_with_password_via_pty(
+        &self,
+        command: &str,
+        password: &str,
+    ) -> io::Result<Output> {
+        use portable_pty::{CommandBuilder, PtySize, native_pty_system};
+        use std::io::{Read, Write};
+
+        let port = self.port;
+        let user = self.user.clone();
